var GOOGLE_NEWS_RSS = (query) => `https://news.google.com/rss/search?q=${encodeURIComponent(query)}&hl=en-US&gl=US&ceid=US:en`;
var BING_NEWS_RSS = (query) => `https://www.bing.com/news/search?q=${encodeURIComponent(query)}&format=rss`;
var CRIME_OR = "(crime OR arrest OR shooting OR robbery OR homicide OR police OR stabbing OR carjacking)";
function parseRSSItems(xml, defaultSource) {
  const items = [];
  const itemRegex = /<item[^>]*>([\s\S]*?)<\/item>/g;
  const matches = xml.matchAll(itemRegex);
  for (const match2 of matches) {
    const itemXml = match2[1] ?? "";
    const title = extractTag(itemXml, "title");
    const link = extractTag(itemXml, "link") || extractAttr(itemXml, "link", "href");
    const pubDate = extractTag(itemXml, "pubDate") || extractTag(itemXml, "published");
    const description = extractTag(itemXml, "description") || extractTag(itemXml, "content:encoded") || extractTag(itemXml, "summary");
    const sourceName = extractTag(itemXml, "source") || extractAttr(itemXml, "source", "url") || defaultSource;
    if (title && link) {
      items.push({
        title: stripHtml(title),
        link: stripHtml(link).trim(),
        pubDate: pubDate ? stripHtml(pubDate).trim() : new Date().toISOString(),
        description: stripHtml(description).slice(0, 500),
        source: stripHtml(sourceName).trim() || defaultSource
      });
    }
  }
  return items;
}
function extractTag(xml, tag) {
  const patterns = [
    new RegExp(`<${tag}[^>]*><!\\[CDATA\\[([\\s\\S]*?)\\]\\]><\\/${tag}>`, "i"),
    new RegExp(`<${tag}[^>]*>([\\s\\S]*?)<\\/${tag}>`, "i")
  ];
  for (const regex of patterns) {
    const m2 = regex.exec(xml);
    if (m2?.[1])
      return m2[1].trim();
  }
  return "";
}
function extractAttr(xml, tag, attr) {
  const regex = new RegExp(`<${tag}[^>]*${attr}=["']([^"']+)["']`, "i");
  const m2 = regex.exec(xml);
  return m2?.[1] ?? "";
}
function stripHtml(html) {
  return html.replace(/<[^>]+>/g, "").replace(/&amp;/g, "&").replace(/&lt;/g, "<").replace(/&gt;/g, ">").replace(/&quot;/g, '"').replace(/&#39;/g, "'").replace(/&nbsp;/g, " ").replace(/\s+/g, " ").trim();
}
