async function queryDataset(dataset, bbox, days) {
  const { domain: domain2, id, columns, datatypes } = dataset;
  const latCol = matchColumn(columns, LAT_PATTERNS);
  const lngCol = matchColumn(columns, LNG_PATTERNS);
  const pointCol = matchPointColumn(columns, datatypes);
  const dateCol = matchColumn(columns, DATE_PATTERNS);
  const typeCol = matchColumn(columns, TYPE_PATTERNS);
  const addressCol = matchColumn(columns, ADDRESS_PATTERNS);
  if (!dateCol || !typeCol)
    return [];
  if (!latCol && !lngCol && !pointCol)
    return [];
  const cutoff = new Date;
  cutoff.setDate(cutoff.getDate() - days);
  const cutoffStr = cutoff.toISOString().slice(0, 19);
  const whereClauses = [];
  whereClauses.push(`${dateCol} > '${cutoffStr}'`);
  if (pointCol) {
    const latSpan = bbox.maxLat - bbox.minLat;
    const lngSpan = bbox.maxLng - bbox.minLng;
    const centerLat = (bbox.minLat + bbox.maxLat) / 2;
    const centerLng = (bbox.minLng + bbox.maxLng) / 2;
    const radiusMeters = Math.max(latSpan, lngSpan) * 111000 / 2;
    whereClauses.push(`within_circle(${pointCol}, ${centerLat}, ${centerLng}, ${radiusMeters})`);
  } else if (latCol && lngCol) {
    if (!isTextColumn(dataset, latCol) && !isTextColumn(dataset, lngCol)) {
      whereClauses.push(`${latCol} > ${bbox.minLat} AND ${latCol} < ${bbox.maxLat} AND ${lngCol} > ${bbox.minLng} AND ${lngCol} < ${bbox.maxLng}`);
    }
  }
  const params = new URLSearchParams({
    $where: whereClauses.join(" AND "),
    $limit: "200",
    $order: `${dateCol} DESC`
  });
  const url2 = `https://${domain2}/resource/${id}.json?${params}`;
  const response = await fetch(url2, {
    headers: {
      Accept: "application/json",
      "User-Agent": "neighborhood-mcp/1.0"
    },
    signal: AbortSignal.timeout(15000)
  });
  if (!response.ok) {
    if (response.status === 400 || response.status === 401 || response.status === 403 || response.status === 404 || response.status === 429) {
      return [];
    }
    throw new Error(`Socrata ${dataset.name} (${domain2}) error: HTTP ${response.status}`);
  }
  const records = await response.json();
  if (!Array.isArray(records) || records.length === 0)
    return [];
  const prefix = `soc-${id}`;
  const results = [];
  for (let i = 0;i < records.length; i++) {
    const record3 = records[i];
    if (!record3)
      continue;
    const coords = extractCoords(record3, latCol, lngCol, pointCol);
    if (!coords)
      continue;
    if (coords.lat < bbox.minLat || coords.lat > bbox.maxLat || coords.lng < bbox.minLng || coords.lng > bbox.maxLng) {
      continue;
    }
    const date6 = parseDate(record3[dateCol]);
    if (!date6)
      continue;
    const type = record3[typeCol] ? String(record3[typeCol]).trim() : "Other";
    const address = addressCol && record3[addressCol] ? String(record3[addressCol]).trim() : "Unknown";
    results.push({
      source: "socrata",
      id: `${prefix}-${i}`,
      type,
      description: `${type} at ${address}`,
      date: date6,
      address,
      lat: coords.lat,
      lng: coords.lng
    });
  }
  return results;
}
async function fetchSocrata(lat, lng, radiusMiles, days) {
  const bbox = buildBoundingBox(lat, lng, radiusMiles);
  const knownDatasets = findKnownDatasets(lat, lng);
  const [catalogDatasets, ...knownWithMeta] = await Promise.all([
    discoverCatalogDatasets().catch(() => []),
    ...knownDatasets.map((ds) => fetchDatasetMetadata(ds))
  ]);
  const seen = new Set;
  const allDatasets = [];
  for (const ds of knownWithMeta) {
    if (!ds)
      continue;
    seen.add(ds.id);
    allDatasets.push(ds);
  }
  for (const ds of catalogDatasets) {
    if (seen.has(ds.id))
      continue;
    seen.add(ds.id);
    allDatasets.push(ds);
  }
  if (allDatasets.length === 0) {
    return [];
  }
  const toQuery = allDatasets.slice(0, 8);
  const results = await Promise.allSettled(toQuery.map((ds) => queryDataset(ds, bbox, days)));
  const incidents = [];
  const errors3 = [];
  for (const result of results) {
    if (result.status === "fulfilled") {
      incidents.push(...result.value);
    } else {
      errors3.push(result.reason instanceof Error ? result.reason.message : String(result.reason));
    }
  }
  if (incidents.length === 0 && errors3.length > 0 && knownDatasets.length > 0) {
    throw new Error(`All Socrata datasets failed: ${errors3.slice(0, 3).join("; ")}`);
  }
  return incidents;
}

// src/sources/spotcrime.ts
var API_KEY = "This-api-key-is-for-2025-commercial-use-exclusively.Only-entities-with-a-Spotcrime-contract-May-use-this-key.Email-feedback-at-spotcrime.com.";
var SEVERITY_MAP = {
  Shooting: "high",
  Assault: "high",
  Robbery: "high",
  Burglary: "medium",
  Arson: "medium",
  Arrest: "low",
  Theft: "low",
  Vandalism: "low",
  Other: "low"
};
function parseSeverity(type) {
  return SEVERITY_MAP[type] ?? "low";
}
function parseSpotCrimeDate(dateStr) {
  const match2 = dateStr.match(/^(\d{2})\/(\d{2})\/(\d{2})\s+(\d{1,2}):(\d{2})\s+(AM|PM)$/i);
  if (!match2)
    return null;
  const [, month, day, year, hourStr, minute, ampm] = match2;
  const fullYear = 2000 + Number(year);
  let hour = Number(hourStr);
  if (ampm?.toUpperCase() === "PM" && hour !== 12)
    hour += 12;
  if (ampm?.toUpperCase() === "AM" && hour === 12)
    hour = 0;
  const d2 = new Date(fullYear, Number(month) - 1, Number(day), hour, Number(minute));
  if (Number.isNaN(d2.getTime()))
    return null;
  return d2.toISOString();
}
async function fetchWithRadius(lat, lng, radius) {
  const params = new URLSearchParams({
    lat: lat.toString(),
    lon: lng.toString(),
    radius: radius.toString(),
    key: API_KEY
  });
  const url2 = `https://api.spotcrime.com/crimes.json?${params}`;
  const response = await fetch(url2, {
    headers: {
      Accept: "application/json",
      "User-Agent": "neighborhood-mcp/1.0"
    },
    signal: AbortSignal.timeout(1e4)
  });
  if (!response.ok) {
    throw new Error(`SpotCrime API error: HTTP ${response.status}`);
  }
  const data = await response.json();
  return data.crimes ?? [];
}
async function fetchSpotCrime(lat, lng, radiusMiles, days) {
  let radius = 0.02;
  let crimes = [];
  const maxAttempts = 5;
  for (let attempt = 0;attempt < maxAttempts; attempt++) {
    const effectiveRadius = Math.min(radius, radiusMiles);
    crimes = await fetchWithRadius(lat, lng, effectiveRadius);
    if (crimes.length >= 5 || effectiveRadius >= radiusMiles)
      break;
    radius *= 2;
  }
  const cutoffMs = Date.now() - days * 24 * 60 * 60 * 1000;
  const prefix = `sc-${Date.now()}`;
  const results = [];
  for (const crime of crimes) {
    const date6 = parseSpotCrimeDate(crime.date);
    if (!date6)
      continue;
    if (new Date(date6).getTime() < cutoffMs)
      continue;
    if (typeof crime.lat !== "number" || typeof crime.lon !== "number" || crime.lat === 0 && crime.lon === 0) {
      continue;
    }
    const type = crime.type || "Other";
    results.push({
      source: "spotcrime",
      id: `${prefix}-${crime.cdid}`,
      type,
      description: `${type} at ${crime.address}`,
      date: date6,
      address: crime.address || "Unknown",
      lat: crime.lat,
      lng: crime.lon,
      url: crime.link,
      severity: parseSeverity(type)
    });
  }
  return results;
}

// src/tools/get-crime-stats.ts
async function getCrimeStats(input) {
  const { zipCode, days = 30 } = input;
  const coords = await zipToCoordinates(zipCode);
  const { lat, lng } = coords;
  const sourceErrors = [];
  const allIncidents = [];
  const radius = 10;
  const fetchers = [
    {
      source: "arcgis",
      fetch: () => fetchArcGIS(lat, lng, radius, days, coords.displayName)
    },
    {
      source: "socrata",
      fetch: () => fetchSocrata(lat, lng, radius, days)
    },
    {
      source: "spotcrime",
      fetch: () => fetchSpotCrime(lat, lng, radius, days)
    }
  ];
  const incidentResults = await Promise.allSettled(fetchers.map(({ fetch: fetch2 }) => fetch2()));
  for (let i = 0;i < incidentResults.length; i++) {
    const result = incidentResults[i];
    const fetcher = fetchers[i];
    if (!result || !fetcher)
      continue;
    if (result.status === "fulfilled") {
      const cutoff = new Date;
      cutoff.setDate(cutoff.getDate() - days);
      allIncidents.push(...result.value.filter((inc) => {
        try {
          return new Date(inc.date) >= cutoff;
        } catch {
          return true;
        }
      }));
    } else {
      const msg = result.reason instanceof Error ? result.reason.message : String(result.reason);
      sourceErrors.push({
        source: fetcher.source,
        error: msg,
        timestamp: new Date().toISOString()
      });
    }
  }
  if (allIncidents.length > 0) {
    try {
      cacheIncidents(zipCode, allIncidents);
    } catch (e) {
      console.error("[cache] write failed:", e);
    }
  }
  if (allIncidents.length === 0) {
    try {
      const cached2 = getCachedIncidents({ zipCode, days: Math.max(days, 90) });
      if (cached2.length > 0) {
        allIncidents.push(...cached2);
        sourceErrors.push({
          source: "cache",
          error: `Live sources returned no data. Showing ${cached2.length} cached results.`,
          timestamp: new Date().toISOString()
        });
      }
    } catch (e) {
      console.error("[cache] read failed:", e);
    }
  }
  let fbiStats = [];
  try {
    fbiStats = await fetchFBIStats(lat, lng, 10);
  } catch (err) {
    const msg = err instanceof Error ? err.message : String(err);
    console.error(`[fbi] stats fetch failed: ${msg}`);
    sourceErrors.push({
      source: "fbi",
      error: msg,
      timestamp: new Date().toISOString()
    });
  }
  const byType = {};
  const bySource = {};
  const bySeverity = {
    high: 0,
    medium: 0,
    low: 0
  };
  for (const incident of allIncidents) {
    byType[incident.type] = (byType[incident.type] ?? 0) + 1;
    bySource[incident.source] = (bySource[incident.source] ?? 0) + 1;
    const sev = incident.severity ?? classifySeverity(incident.type);
    bySeverity[sev] = (bySeverity[sev] ?? 0) + 1;
  }
  for (const agency of fbiStats) {
    bySource[`fbi-${agency.ori}`] = agency.offenses.reduce((sum, o) => sum + o.count, 0);
    for (const offense of agency.offenses) {
      byType[offense.type] = (byType[offense.type] ?? 0) + offense.count;
    }
  }
  const totalIncidents = allIncidents.length;
  const topTypes = Object.entries(byType).sort(([, a2], [, b2]) => b2 - a2).slice(0, 25).map(([type, count]) => ({
    type,
    count,
    percentage: totalIncidents > 0 ? Math.round(count / totalIncidents * 100 * 10) / 10 : 0
  }));
  const trend = computeTrend(allIncidents, days);
  return {
    zipCode,
    days,
    totalIncidents,
    byType,
    bySource,
    bySeverity,
    topTypes,
    trend,
    generatedAt: new Date().toISOString(),
    sourceErrors
  };
}
function computeTrend(incidents, days) {
  if (incidents.length < 4)
    return "unknown";
  const now = Date.now();
  const halfMs = days / 2 * 24 * 60 * 60 * 1000;
  const midpoint = now - halfMs;
  let firstHalf = 0;
  let secondHalf = 0;
  for (const incident of incidents) {
    const ms = new Date(incident.date).getTime();
    if (ms < midpoint) {
      firstHalf++;
    } else {
      secondHalf++;
    }
  }
  if (firstHalf === 0)
    return "unknown";
  const ratio = secondHalf / firstHalf;
  if (ratio > 1.2)
    return "increasing";
  if (ratio < 0.8)
    return "decreasing";
  return "stable";
}

// src/tools/get-incidents.ts
var ALL_SOURCES = ["arcgis", "socrata", "spotcrime"];
async function getIncidents(input) {
  const { zipCode, radius = 5, days = 30 } = input;
  const enabledSources = input.sources ?? ALL_SOURCES;
  const coords = await zipToCoordinates(zipCode);
  const { lat, lng } = coords;
  const allFetchers = [
    {
      source: "arcgis",
      fetch: () => fetchArcGIS(lat, lng, radius, days, coords.displayName)
    },
    {
      source: "socrata",
      fetch: () => fetchSocrata(lat, lng, radius, days)
    },
    {
      source: "spotcrime",
      fetch: () => fetchSpotCrime(lat, lng, radius, days)
    }
  ];
  const sourceFetchers = allFetchers.filter((f2) => enabledSources.includes(f2.source));
  const results = await Promise.allSettled(sourceFetchers.map(({ fetch: fetch2 }) => fetch2()));
  const freshIncidents = [];
  const sourceErrors = [];
  const failedSources = [];
  for (let i = 0;i < results.length; i++) {
    const result = results[i];
    const fetcher = sourceFetchers[i];
    if (!result || !fetcher)
      continue;
    if (result.status === "fulfilled") {
      freshIncidents.push(...result.value);
    } else {
      const errorMsg = result.reason instanceof Error ? result.reason.message : String(result.reason);
      console.error(`[${fetcher.source}] fetch failed: ${errorMsg}`);
      sourceErrors.push({
        source: fetcher.source,
        error: errorMsg,
        timestamp: new Date().toISOString()
      });
      failedSources.push(fetcher.source);
    }
  }
  if (freshIncidents.length > 0) {
    try {
      cacheIncidents(zipCode, freshIncidents);
    } catch (e) {
      console.error("[cache] write failed:", e);
    }
  }
  let allIncidents = freshIncidents;
  if (failedSources.length > 0) {
    try {
      const cached2 = getCachedIncidents({
        zipCode,
        days: Math.max(days, 90),
        sources: failedSources
      });
      if (cached2.length > 0) {
        allIncidents = [...freshIncidents, ...cached2];
        for (const err of sourceErrors) {
          if (failedSources.includes(err.source)) {
            err.error += ` (serving ${cached2.filter((c) => c.source === err.source).length} cached results)`;
          }
        }
      }
    } catch (e) {
      console.error("[cache] read failed:", e);
    }
  }
  if (allIncidents.length === 0) {
    try {
      const cached2 = getCachedIncidents({ zipCode, days: 365 });
      if (cached2.length > 0) {
        allIncidents = cached2;
        sourceErrors.push({
          source: "cache",
          error: `All live sources failed. Showing ${cached2.length} cached results.`,
          timestamp: new Date().toISOString()
        });
      }
    } catch (e) {
      console.error("[cache] fallback read failed:", e);
    }
  }
  const cutoff = new Date;
  cutoff.setDate(cutoff.getDate() - days);
  const filtered = allIncidents.filter((incident) => {
    try {
      return new Date(incident.date) >= cutoff;
    } catch {
      return true;
    }
  });
  const seen = new Set;
  const deduped = filtered.filter((inc) => {
    if (seen.has(inc.id))
      return false;
    seen.add(inc.id);
    return true;
  });
  const final = deduplicateSpatial(deduped);
  return buildFeatureCollection(zipCode, radius, days, final, sourceErrors);
}
function deduplicateSpatial(incidents) {
  const RADIUS_DEG = 100 / 111000;
  const TIME_WINDOW_MS = 24 * 60 * 60 * 1000;
  const sorted = [...incidents].sort((a2, b2) => {
    const scoreA = (a2.description?.length || 0) + (a2.url ? 100 : 0);
    const scoreB = (b2.description?.length || 0) + (b2.url ? 100 : 0);
    return scoreB - scoreA;
  });
  const kept = [];
  for (const inc of sorted) {
    const isDupe = kept.some((k2) => {
      if (k2.type.toLowerCase() !== inc.type.toLowerCase())
        return false;
      const timeDiff = Math.abs(new Date(k2.date).getTime() - new Date(inc.date).getTime());
      if (timeDiff > TIME_WINDOW_MS)
        return false;
      const latDiff = Math.abs(k2.lat - inc.lat);
      const lngDiff = Math.abs(k2.lng - inc.lng);
      return latDiff < RADIUS_DEG && lngDiff < RADIUS_DEG;
    });
    if (!isDupe)
      kept.push(inc);
  }
  return kept;
}

// src/tools/list-sources.ts
var SOURCE_METADATA = [
  {
    name: "arcgis",
    label: "ArcGIS Open Data",
    coverage: "County/city GIS portals with public crime layers",
    updateFrequency: "Varies by agency — typically daily to weekly",
    requiresApiKey: false,
    unlocks: "GIS-sourced crime data from local government open data portals",
    testUrl: "https://www.arcgis.com/"
  },
  {
    name: "socrata",
    label: "Socrata Open Data (SODA API)",
    coverage: "Hundreds of US city police department open data portals with real-time crime incident data",
    updateFrequency: "Varies by city — typically daily",
    requiresApiKey: false,
    unlocks: "Point-level crime incident data from city open data portals (Chicago, NYC, Austin, etc.)",
    testUrl: "https://api.us.socrata.com/api/catalog/v1?limit=1"
  },
  {
    name: "spotcrime",
    label: "SpotCrime",
    coverage: "Nationwide US — aggregates police blotter data from 1,000+ agencies",
    updateFrequency: "Daily",
    requiresApiKey: false,
    unlocks: "Point-level crime incidents with type classification from police blotters",
    testUrl: "https://api.spotcrime.com/crimes.json?lat=0&lon=0&radius=0.01&key=This-api-key-is-for-2025-commercial-use-exclusively.Only-entities-with-a-Spotcrime-contract-May-use-this-key.Email-feedback-at-spotcrime.com."
  }
];
async function checkSourceOnline(testUrl) {
  try {
    const response = await fetch(testUrl, {
      method: "HEAD",
      signal: AbortSignal.timeout(5000),
      headers: { "User-Agent": "neighborhood-mcp/1.0" }
    });
    return response.ok || response.status < 500;
  } catch {
    return false;
  }
}
async function listSources() {
  const checks4 = await Promise.allSettled(SOURCE_METADATA.map(async (meta3) => {
    const online = await checkSourceOnline(meta3.testUrl);
    const hasApiKey = meta3.requiresApiKey ? Boolean(meta3.apiKeyEnvVar && process.env[meta3.apiKeyEnvVar]) : true;
    const status = {
      name: meta3.name,
      label: meta3.label,
      online,
      coverage: meta3.coverage,
      updateFrequency: meta3.updateFrequency,
      requiresApiKey: meta3.requiresApiKey,
      apiKeyEnvVar: meta3.apiKeyEnvVar,
      hasApiKey,
      lastChecked: new Date().toISOString()
    };
    if (meta3.requiresApiKey && !hasApiKey) {
      status.error = `Add ${meta3.apiKeyEnvVar} to unlock: ${meta3.unlocks}`;
    }
    return status;
  }));
  const sources = checks4.map((result, i) => {
    const meta3 = SOURCE_METADATA[i];
    if (result.status === "fulfilled")
      return result.value;
    return {
      name: meta3?.name ?? "unknown",
      label: meta3?.label ?? "Unknown",
      online: false,
      coverage: meta3?.coverage ?? "Unknown",
      updateFrequency: meta3?.updateFrequency ?? "Unknown",
      requiresApiKey: meta3?.requiresApiKey ?? false,
      hasApiKey: false,
      lastChecked: new Date().toISOString(),
      error: result.reason instanceof Error ? result.reason.message : String(result.reason)
    };
  });
  const active = sources.filter((s2) => s2.online && s2.hasApiKey).length;
  const available = sources.filter((s2) => s2.online && !s2.hasApiKey && s2.requiresApiKey).length;
  const missingKeys = SOURCE_METADATA.filter((m2) => m2.requiresApiKey && m2.apiKeyEnvVar && !process.env[m2.apiKeyEnvVar]).map((m2) => `${m2.apiKeyEnvVar} — ${m2.unlocks} (free: ${m2.signupUrl})`);
  const tip = missingKeys.length > 0 ? `Connect ${missingKeys.length} more API${missingKeys.length > 1 ? "s" : ""} for broader coverage. Add keys to ~/.config/neighborhood/.env` : "All available sources are connected.";
  return {
    sources,
    summary: {
      active,
      available,
      total: sources.length,
      missingKeys,
      tip
    }
  };
}

